import{_ as e,o,c as l,a2 as a}from"./chunks/framework.Pywvta2k.js";const q=JSON.parse('{"title":"脾胃论","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/03-宋金元/03-脾胃论（李东垣）.md","filePath":"tcm-data/03-宋金元/03-脾胃论（李东垣）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/03-宋金元/03-脾胃论（李东垣）.md"};function n(s,t,i,d,g,h){return o(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="脾胃论" tabindex="-1">脾胃论 <a class="header-anchor" href="#脾胃论" aria-label="Permalink to &quot;脾胃论&quot;">​</a></h1><blockquote><p>李东垣（1180-1251年），河北正定人 金元四大家之一，&quot;补土派&quot;创始人 代表作：《脾胃论》《内外伤辨惑论》《兰室秘藏》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名杲，字明之，晚号东垣老人</li><li><strong>师承</strong>：张元素（易水学派）</li><li><strong>时代背景</strong>：金元战乱，人民饥饱不调、劳役过度，脾胃病多发</li><li><strong>学术地位</strong>：金元四大家之一，&quot;<strong>内伤脾胃，百病由生</strong>&quot;</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-内伤脾胃-百病由生-——-补土派的核心" tabindex="-1">1. 内伤脾胃，百病由生 —— 补土派的核心 <a class="header-anchor" href="#_1-内伤脾胃-百病由生-——-补土派的核心" aria-label="Permalink to &quot;1. 内伤脾胃，百病由生 —— 补土派的核心&quot;">​</a></h3><blockquote><p><strong>「脾胃之气既伤，而元气亦不能充，而诸病之所由生也。」</strong></p></blockquote><p>李东垣认为：<strong>脾胃为元气之本</strong>。脾胃损伤 → 元气不足 → 百病丛生。这个理论直接影响了黄元御&quot;中气为轴&quot;的思想。</p><h3 id="_2-阴火论-核心中的核心" tabindex="-1">2. 阴火论（核心中的核心） <a class="header-anchor" href="#_2-阴火论-核心中的核心" aria-label="Permalink to &quot;2. 阴火论（核心中的核心）&quot;">​</a></h3><blockquote><p><strong>「脾胃气虚，则下流于肾，阴火得以乘其土位。」</strong></p></blockquote><p><strong>&quot;阴火&quot;是什么？</strong></p><ul><li>不是实火，而是<strong>脾胃虚寒、清阳不升 → 浊阴下流 → 郁而化火</strong></li><li>这种火的特点是：<strong>上热（口疮、烦躁）+ 下寒（腹冷、便溏）</strong></li><li><strong>治疗不可苦寒清热</strong>，而应<strong>升阳补气 → 阴火自降</strong></li></ul><p><strong>这与普光师兄的&quot;口渴不贪凉&quot;完全吻合——都是阴火。</strong></p><h3 id="_3-升阳泻火——独特的治法" tabindex="-1">3. 升阳泻火——独特的治法 <a class="header-anchor" href="#_3-升阳泻火——独特的治法" aria-label="Permalink to &quot;3. 升阳泻火——独特的治法&quot;">​</a></h3><p>李东垣创制了<strong>升阳药 + 补气药 + 少量清热药</strong>的配伍模式：</p><ul><li>升阳：升麻、柴胡、羌活（升清阳）</li><li>补气：人参、黄芪、炙甘草（补中气）</li><li>清热（少量）：黄连、黄芩、黄柏（清阴火，不可过量）</li></ul><h3 id="_4-甘温除大热" tabindex="-1">4. 甘温除大热 <a class="header-anchor" href="#_4-甘温除大热" aria-label="Permalink to &quot;4. 甘温除大热&quot;">​</a></h3><blockquote><p><strong>「惟当以甘温之剂，补其中，升其阳，甘寒以泻其火则愈。」</strong></p></blockquote><p><strong>&quot;甘温除热&quot;</strong>——用甘温药治疗虚热证，是李东垣对中医治法的重大贡献。这也解释了为什么普光的&quot;上热&quot;不能用大量苦寒药。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>补中益气汤</strong></td><td style="text-align:left;">黄芪、人参、白术、炙甘草、当归、陈皮、升麻、柴胡</td><td style="text-align:left;">脾胃气虚，少气懒言</td><td style="text-align:left;">疲劳综合征、胃下垂</td></tr><tr><td style="text-align:left;"><strong>升阳益胃汤</strong></td><td style="text-align:left;">黄芪、人参、白术、甘草、羌活、独活、防风、柴胡、黄连、泽泻、陈皮、半夏、茯苓</td><td style="text-align:left;">脾胃虚弱，怠惰嗜卧</td><td style="text-align:left;">慢性胃肠炎</td></tr><tr><td style="text-align:left;"><strong>黄芪人参汤</strong></td><td style="text-align:left;">黄芪、人参、升麻、炙甘草、苍术、白术、黄柏、神曲、当归、麦冬、五味子</td><td style="text-align:left;">暑伤元气</td><td style="text-align:left;">夏季疲劳</td></tr><tr><td style="text-align:left;"><strong>当归六黄汤</strong></td><td style="text-align:left;">当归、生地、熟地、黄连、黄芩、黄柏、黄芪</td><td style="text-align:left;">阴虚盗汗</td><td style="text-align:left;">更年期盗汗</td></tr><tr><td style="text-align:left;"><strong>普济消毒饮</strong></td><td style="text-align:left;">黄芩、黄连、陈皮、甘草、玄参、柴胡、桔梗、连翘、板蓝根、马勃、牛蒡子、薄荷、僵蚕、升麻</td><td style="text-align:left;">大头瘟</td><td style="text-align:left;">腮腺炎、头面部丹毒</td></tr></tbody></table><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><blockquote><p><strong>「内伤脾胃，百病由生。」</strong></p></blockquote><blockquote><p><strong>「脾胃之气既伤，而元气亦不能充。」</strong></p></blockquote><blockquote><p><strong>「夫脾胃不足，皆为血病。盖脾胃为血气阴阳之根蒂也。」</strong></p></blockquote><blockquote><p><strong>「若饮食不节，寒温不适，则脾胃乃伤；喜怒忧恐，损耗元气。」</strong></p></blockquote><blockquote><p><strong>「惟当以甘温之剂，补其中，升其阳。」</strong></p></blockquote><blockquote><p><strong>「胃中元气盛，则能食而不伤，过时而不饥。」</strong></p></blockquote><blockquote><p><strong>「百病皆由脾胃衰而生。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="黄元御与李东垣" tabindex="-1">黄元御与李东垣 <a class="header-anchor" href="#黄元御与李东垣" aria-label="Permalink to &quot;黄元御与李东垣&quot;">​</a></h3><p>黄元御的<strong>黄芽汤（人参、甘草、茯苓、干姜）</strong> 直接继承和简化了李东垣的补土思路。两人都认为脾胃（中气）是生命枢轴，但黄元御更强调&quot;左升右降&quot;的圆运动模型，而李东垣更重视&quot;升阳&quot;。</p><h3 id="彭子益-李可" tabindex="-1">彭子益（李可） <a class="header-anchor" href="#彭子益-李可" aria-label="Permalink to &quot;彭子益（李可）&quot;">​</a></h3><p>《圆运动的古中医学》中大量引用了李东垣的升阳法，认为中气不足是圆运动失常的根本原因。</p><h3 id="现代应用" tabindex="-1">现代应用 <a class="header-anchor" href="#现代应用" aria-label="Permalink to &quot;现代应用&quot;">​</a></h3><ul><li>补中益气汤是临床最常用的方剂之一</li><li>&quot;甘温除热&quot;治疗虚热内伤发热</li><li>脾胃学说指导慢性病调养</li></ul><hr><p><em>本条目为精简框架版。李东垣的系列方剂（《脾胃论》载方60余首、《兰室秘藏》载方280余首）可扩展为独立专题。</em></p>',43)])])}const c=e(r,[["render",n]]);export{q as __pageData,c as default};
